from PIL import Image

img = Image.open('/app/files/cca530fc-4052-43b2-b130-b30968d8aa44.png')
h, w = img.size
print(f"Image size: {w}x{h}")

LIGHT_SQ = (238, 238, 210)
DARK_SQ = (118, 150, 86)

def color_diff(c1, c2):
    return sum(abs(c1[i] - c2[i]) for i in range(3))

def color_brightness(c):
    return (c[0] + c[1] + c[2]) / 3

def is_light_square(row, col):
    return (row + col) % 2 == 0

def sample_point(img, row, col, rel_x, rel_y, size=3):
    sq_h = h // 8
    sq_w = w // 8
    cx = col * sq_w + int(rel_x * sq_w)
    cy = row * sq_h + int(rel_y * sq_h)

    pixels = []
    for dy in range(-size, size+1):
        for dx in range(-size, size+1):
            px, py = cx + dx, cy + dy
            if 0 <= px < w and 0 <= py < h:
                pixels.append(img.getpixel((px, py)))

    if not pixels:
        return (0, 0, 0)
    r = sum(p[0] for p in pixels) // len(pixels)
    g = sum(p[1] for p in pixels) // len(pixels)
    b = sum(p[2] for p in pixels) // len(pixels)
    return (r, g, b)

def sample_outer_ring(img, row, col, inner=0.2, outer=0.4, size=3):
    """Sample the outer ring of a square"""
    sq_h = h // 8
    sq_w = w // 8

    pixels = []
    for rel_x in [inner, 1-inner]:
        for rel_y in [inner, 1-inner]:
            pass

    # Sample at multiple points on the ring
    for i in range(10):
        t = i / 10
        # Top edge
        cx = col * sq_w + int(t * sq_w)
        cy = row * sq_h + int(outer * sq_h)
        for dx in range(-size, size+1):
            px, py = cx + dx, cy + dy if (cy + dy) < (row + 1) * sq_h else cy
            if 0 <= px < w and 0 <= py < h:
                pixels.append(img.getpixel((px, py)))

    if not pixels:
        return (0, 0, 0)
    r = sum(p[0] for p in pixels) // len(pixels)
    g = sum(p[1] for p in pixels) // len(pixels)
    b = sum(p[2] for p in pixels) // len(pixels)
    return (r, g, b)

print("\n=== ALL SQUARES ANALYSIS ===")
print("Expected bg: L=light square, D=dark square")
print()

for row in range(8):
    for col in range(8):
        sq = chr(97+col) + str(8-row)

        # Sample corners
        corners = [
            sample_point(img, row, col, 0.15, 0.15, 5),
            sample_point(img, row, col, 0.85, 0.15, 5),
            sample_point(img, row, col, 0.15, 0.85, 5),
            sample_point(img, row, col, 0.85, 0.85, 5),
        ]
        avg_corner = tuple(sum(c[i] for c in corners) // 4 for i in range(3))

        # Sample center
        center = sample_point(img, row, col, 0.5, 0.5, 12)

        # Sample a few more points in the center area
        center_pts = [
            sample_point(img, row, col, 0.5, 0.5, 8),
            sample_point(img, row, col, 0.4, 0.5, 5),
            sample_point(img, row, col, 0.6, 0.5, 5),
            sample_point(img, row, col, 0.5, 0.4, 5),
            sample_point(img, row, col, 0.5, 0.6, 5),
        ]
        avg_center = tuple(sum(c[i] for c in center_pts) // 5 for i in range(3))

        expected_bg = LIGHT_SQ if is_light_square(row, col) else DARK_SQ
        sq_type = 'L' if is_light_square(row, col) else 'D'
        corner_diff = color_diff(avg_corner, expected_bg)
        center_diff = color_diff(avg_center, expected_bg)
        center_brightness = color_brightness(avg_center)

        # Print all squares with their data
        marker = ''
        if corner_diff > 100:
            marker = '(BORDER)'
        elif center_diff > 60:
            if center_brightness > 170:
                marker = '(W)'
            elif center_brightness < 110:
                marker = '(B)'
            else:
                marker = f'(?:b={center_brightness:.0f})'

        print(f"{sq}({sq_type}): corner={avg_corner} ctr={avg_center} diff={center_diff} bri={center_brightness:.0f} {marker}")
